import json
from datetime import datetime
def task_func(json_data):
    data = json.loads(json_data)

    utc_datetime_str = data.get('utc_datetime')

    if not utc_datetime_str:
        raise ValueError("The JSON data must contain a 'utc_datetime' key with a valid datetime string.")

    utc_datetime = datetime.fromisoformat(utc_datetime_str)

    return utc_datetime.weekday() in (5, 6)

