import subprocess
import psutil
import time
def task_func(process_name: str) -> str:
    is_running = any([proc for proc in psutil.process_iter() if proc.name() == process_name])

    if is_running:
        for proc in psutil.process_iter():
            if proc.name() == process_name:
                proc.terminate()
                time.sleep(5)
        subprocess.Popen(process_name)
        return f"Process found. Restarting {process_name}."
    else:
        subprocess.Popen(process_name)
        return f"Process not found. Starting {process_name}."

import subprocess
import os
import threading
def task_func(script_path: str, timeout: int = 60) -> str:
    if not os.path.exists(script_path):
        raise FileNotFoundError(f"Script not found at path: {script_path}")

    process = subprocess.Popen(['python', script_path], stdout=subprocess.PIPE, stderr=subprocess.PIPE)

    def kill_process():
        if process.poll() is None:
            process.terminate()

    timer = threading.Timer(timeout, kill_process)
    timer.start()

    stdout, stderr = process.communicate()
    timer.cancel()

    if process.returncode == 0:
        return "Script executed successfully."
    else:
        return "Terminating process due to timeout."

